import{_ as a,o as t,c as r,a4 as o}from"./chunks/framework.Bz0lZ1uX.js";const q=JSON.parse('{"title":"事件素材","description":"","frontmatter":{},"headers":[],"relativePath":"materials/事件素材/index.md","filePath":"materials/事件素材/index.md","lastUpdated":null}'),e={name:"materials/事件素材/index.md"},n=o('<h1 id="事件素材" tabindex="-1">事件素材 <a class="header-anchor" href="#事件素材" aria-label="Permalink to &quot;事件素材&quot;">​</a></h1><p>事件素材以具体的社会事件、新闻事件为论据，具有时效性强、说服力高的特点。</p><h2 id="科技创新类" tabindex="-1">科技创新类 <a class="header-anchor" href="#科技创新类" aria-label="Permalink to &quot;科技创新类&quot;">​</a></h2><h3 id="嫦娥探月工程" tabindex="-1">嫦娥探月工程 <a class="header-anchor" href="#嫦娥探月工程" aria-label="Permalink to &quot;嫦娥探月工程&quot;">​</a></h3><p><strong>标签</strong>: #航天 #科技创新 #国家实力 #探索精神</p><p><strong>事件概述</strong>: 从2004年嫦娥工程立项到嫦娥五号成功带回月球样本，中国成为第三个实现月球采样返回的国家。嫦娥六号更实现了人类首次月球背面采样返回。</p><p><strong>适用主题</strong>: 科技自立自强、探索精神、国家实力、梦想实现</p><p><strong>论点示例</strong>: 科技创新需要久久为功的坚持精神</p><h3 id="c919大飞机商业首飞" tabindex="-1">C919大飞机商业首飞 <a class="header-anchor" href="#c919大飞机商业首飞" aria-label="Permalink to &quot;C919大飞机商业首飞&quot;">​</a></h3><p><strong>标签</strong>: #航空 #自主创新 #制造业 #突破</p><p><strong>事件概述</strong>: 2023年5月28日，国产大飞机C919完成首次商业飞行，标志着中国成为世界上少数具备研制大型客机能力的国家。</p><p><strong>适用主题</strong>: 自主创新、大国重器、打破垄断、产业升级</p><h2 id="社会民生类" tabindex="-1">社会民生类 <a class="header-anchor" href="#社会民生类" aria-label="Permalink to &quot;社会民生类&quot;">​</a></h2><h3 id="脱贫攻坚全面胜利" tabindex="-1">脱贫攻坚全面胜利 <a class="header-anchor" href="#脱贫攻坚全面胜利" aria-label="Permalink to &quot;脱贫攻坚全面胜利&quot;">​</a></h3><p><strong>标签</strong>: #脱贫 #民生 #共同富裕 #社会责任</p><p><strong>事件概述</strong>: 经过8年持续奋斗，中国现行标准下9899万农村贫困人口全部脱贫，832个贫困县全部摘帽，历史性地解决了绝对贫困问题。</p><p><strong>适用主题</strong>: 共同富裕、责任担当、制度优势、以人为本</p><h3 id="河南暴雨救援" tabindex="-1">河南暴雨救援 <a class="header-anchor" href="#河南暴雨救援" aria-label="Permalink to &quot;河南暴雨救援&quot;">​</a></h3><p><strong>标签</strong>: #灾难 #互助 #志愿者 #社会责任</p><p><strong>事件概述</strong>: 2021年7月河南遭遇特大暴雨灾害，全国各地迅速响应，民间救援队、志愿者、企业纷纷伸出援手，展现了强大的社会凝聚力。</p><p><strong>适用主题</strong>: 众志成城、社会责任感、守望相助、人间大爱</p><h2 id="教育类" tabindex="-1">教育类 <a class="header-anchor" href="#教育类" aria-label="Permalink to &quot;教育类&quot;">​</a></h2><h3 id="双减-政策实施" tabindex="-1">&quot;双减&quot;政策实施 <a class="header-anchor" href="#双减-政策实施" aria-label="Permalink to &quot;&quot;双减&quot;政策实施&quot;">​</a></h3><p><strong>标签</strong>: #教育 #减负 #改革 #学生发展</p><p><strong>事件概述</strong>: 2021年&quot;双减&quot;政策出台，旨在减轻义务教育阶段学生作业负担和校外培训负担，推动教育回归本质，促进学生全面发展。</p><p><strong>适用主题</strong>: 教育改革、全面发展、减负增效、长远眼光</p><h3 id="高考作文引热议" tabindex="-1">高考作文引热议 <a class="header-anchor" href="#高考作文引热议" aria-label="Permalink to &quot;高考作文引热议&quot;">​</a></h3><p><strong>标签</strong>: #高考 #教育公平 #人才选拔 #社会关注</p><p><strong>事件概述</strong>: 每年高考作文题目都会引发社会广泛讨论，反映社会对教育的关注和对人才评价标准的思考。</p><p><strong>适用主题</strong>: 教育公平、独立思考、时代精神、价值导向</p><h2 id="环保类" tabindex="-1">环保类 <a class="header-anchor" href="#环保类" aria-label="Permalink to &quot;环保类&quot;">​</a></h2><h3 id="塞罕坝林场奇迹" tabindex="-1">塞罕坝林场奇迹 <a class="header-anchor" href="#塞罕坝林场奇迹" aria-label="Permalink to &quot;塞罕坝林场奇迹&quot;">​</a></h3><p><strong>标签</strong>: #环保 #生态建设 #坚持 #绿色发展的</p><p><strong>事件概述</strong>: 三代务林人用55年时间在荒漠上创造出百万亩人工林海，将&quot;黄沙遮天日&quot;变成&quot;河的源头、云的故乡、花的世界、林的海洋&quot;。</p><p><strong>适用主题</strong>: 坚持、生态文明建设、绿色发展、功在当代利在千秋</p><h3 id="长江十年禁渔" tabindex="-1">长江十年禁渔 <a class="header-anchor" href="#长江十年禁渔" aria-label="Permalink to &quot;长江十年禁渔&quot;">​</a></h3><p><strong>标签</strong>: #环保 #生态保护 #可持续发展 #长远利益</p><p><strong>事件概述</strong>: 2021年起长江流域实行十年禁渔，30多万渔民退捕转产，以短期利益牺牲换取长江生态的长期恢复。</p><p><strong>适用主题</strong>: 长远利益与短期利益、生态保护、可持续发展</p><h2 id="使用建议" tabindex="-1">使用建议 <a class="header-anchor" href="#使用建议" aria-label="Permalink to &quot;使用建议&quot;">​</a></h2><ol><li>注意事件的真实性，使用权威来源</li><li>交代事件背景，但重点放在事件体现的道理上</li><li>事件叙述要简明扼要，避免过于冗长</li><li>结合事件进行分析议论，做到叙议结合</li><li>关注时事，积累最新事件素材</li></ol>',41),s=[n];function i(l,h,p,d,g,c){return t(),r("div",null,s)}const b=a(e,[["render",i]]);export{q as __pageData,b as default};
